sql:
SELECT game_id, score, MIN(training_time) AS minimum_training_time
FROM variant_performance
GROUP BY game_id, score;

external_knowledge:
- 'Champions of each game' refers to the algorithms with the highest score for a particular game, considering the least training time and the least number of episodes; 
- 'Name of their winning formula' refers to the algorithm name; 
- 'Secret ingredient' refers to the variant name.

sql:
SELECT variant_id, COUNT(evaluation_id) AS number_of_evaluations
FROM variant_evaluations
GROUP BY variant_id;

SELECT SUM(training_time) AS total_training_time
FROM (
    SELECT training_time FROM evaluations
    UNION ALL
    SELECT training_time FROM variant_evaluations
) AS combined_training_times;

SELECT variant_name
FROM algorithm_variants
WHERE created_by = 0;

SELECT created_by
FROM algorithm_variants
WHERE variant_id = 0;
